export function createEmptyDiscoveryJob(seed) {
    return {
        id: seed.id,
        source: seed.source,
        title: seed.title,
        company: seed.company,
        location: seed.location,
        description: seed.description,
        jobUrl: seed.jobUrl,
        externalUrl: "",
        atsType: "unknown",
        atsIdentifier: "",
        postedAt: seed.postedAt ?? null,
        extractedAt: seed.extractedAt,
        salary: "",
        salaryRaw: "",
        salaryMin: "",
        salaryMax: "",
        salaryCurrency: "",
        salaryPeriod: "",
        jobType: "",
        workArrangement: "",
        applicantCount: "",
        requiredSkills: "",
        techStack: "[]",
        experienceLevel: "",
        experienceYears: null,
        isPrRequired: false,
        securityClearance: "",
        prConfidence: "",
        prReasoning: "",
        companyLogoUrl: "",
        isAlreadyApplied: false,
        appliedDateUtc: "",
    };
}
